create table if not exists public.trade_spiff_rules (id uuid primary key default gen_random_uuid(), store_id uuid references public.stores(id) on delete cascade, effective_month date not null, high_acv_threshold numeric not null default 99999, low_acv_amount numeric not null default 500, high_acv_amount numeric not null default 1000, active boolean not null default true, created_at timestamptz not null default now());